     1→/**
     2→ * Field Components
     3→ * Individual field types for form rendering
     4→ */
     5→
     6→import { useState } from 'react';
     7→import { Upload, X, FileIcon } from 'lucide-react';
     8→import type { FormField, FileUploadAnswer, FormAnswerValue } from '../../types/forms';
     9→
    10→/**
    11→ * Common props for field components
    12→ * Value and onChange are typed loosely here because each field type
    13→ * handles its own specific value type internally
    14→ */
    15→interface FieldComponentProps {
    16→  field: FormField;
    17→  value: FormAnswerValue;
    18→  onChange: (value: FormAnswerValue) => void;
    19→  error?: string;
    20→}
    21→
    22→// Helper to safely convert value to string for text inputs
    23→const toStringValue = (value: FormAnswerValue): string => {
    24→  if (value === null || value === undefined) return '';
    25→  if (typeof value === 'string') return value;
    26→  if (typeof value === 'number') return String(value);
    27→  return '';
    28→};
    29→
    30→// Helper to safely convert value to number
    31→const toNumberValue = (value: FormAnswerValue): number | '' => {
    32→  if (value === null || value === undefined) return '';
    33→  if (typeof value === 'number') return value;
    34→  if (typeof value === 'string' && value !== '') return Number(value);
    35→  return '';
    36→};
    37→
    38→// Helper to safely convert value to boolean
    39→const toBooleanValue = (value: FormAnswerValue): boolean => {
    40→  if (typeof value === 'boolean') return value;
    41→  return false;
    42→};
    43→
    44→// Helper to safely convert value to string array
    45→const toStringArrayValue = (value: FormAnswerValue): string[] => {
    46→  if (Array.isArray(value) && value.every(v => typeof v === 'string')) {
    47→    return value as string[];
    48→  }
    49→  return [];
    50→};
    51→
    52→// Helper to safely convert value to FileUploadAnswer array
    53→const toFileArrayValue = (value: FormAnswerValue): FileUploadAnswer[] => {
    54→  if (Array.isArray(value)) {
    55→    return value.filter((v): v is FileUploadAnswer =>
    56→      typeof v === 'object' && v !== null && 'fileName' in v
    57→    );
    58→  }
    59→  if (value && typeof value === 'object' && 'fileName' in value) {
    60→    return [value as FileUploadAnswer];
    61→  }
    62→  return [];
    63→};
    64→
    65→export function TextField({ field, value, onChange, error }: FieldComponentProps) {
    66→  return (
    67→    <div>
    68→      <label className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-1">
    69→        {field.label}
    70→        {field.required && <span className="text-red-500 ml-1">*</span>}
    71→      </label>
    72→      {field.description && (
    73→        <p className="text-xs text-text-light-tertiary dark:text-text-dark-tertiary mb-2">
    74→          {field.description}
    75→        </p>
    76→      )}
    77→      <input
    78→        type="text"
    79→        value={toStringValue(value)}
    80→        onChange={(e) => onChange(e.target.value)}
    81→        required={field.required}
    82→        className="w-full px-3 py-2 bg-background-light dark:bg-background-dark border border-border-light dark:border-border-dark rounded-lg focus:outline-none focus:ring-2 focus:ring-primary-light dark:focus:ring-primary-dark"
    83→      />
    84→      {error && <p className="text-xs text-red-500 mt-1">{error}</p>}
    85→    </div>
    86→  );
    87→}
