   217→export function MultiSelectField({ field, value, onChange, error }: FieldComponentProps) {
   218→  const selectedValues = toStringArrayValue(value);
   219→
   220→  const handleToggle = (option: string) => {
   221→    if (selectedValues.includes(option)) {
   222→      onChange(selectedValues.filter((v) => v !== option));
   223→    } else {
   224→      onChange([...selectedValues, option]);
   225→    }
   226→  };
   227→
   228→  return (
   229→    <div>
   230→      <label className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-1">
   231→        {field.label}
   232→        {field.required && <span className="text-red-500 ml-1">*</span>}
   233→      </label>
   234→      {field.description && (
   235→        <p className="text-xs text-text-light-tertiary dark:text-text-dark-tertiary mb-2">
   236→          {field.description}
   237→        </p>
   238→      )}
   239→      <div className="space-y-2">
   240→        {field.options?.map((option) => (
   241→          <label key={option} className="flex items-center gap-2 cursor-pointer">
   242→            <input
   243→              type="checkbox"
   244→              checked={selectedValues.includes(option)}
   245→              onChange={() => handleToggle(option)}
   246→              className="w-4 h-4"
   247→            />
   248→            <span className="text-sm text-text-light-primary dark:text-text-dark-primary">
   249→              {option}
   250→            </span>
   251→          </label>
   252→        ))}
   253→      </div>
   254→      {error && <p className="text-xs text-red-500 mt-1">{error}</p>}
   255→    </div>
   256→  );
   257→}
