   402→export function FileUploadField({ field, value, onChange, error }: FieldComponentProps) {
   403→  const [uploadError, setUploadError] = useState<string>('');
   404→
   405→  // Default config if not specified
   406→  const config = field.fileConfig || {
   407→    maxSizeMB: 10,
   408→    allowedTypes: ['image/*', 'application/pdf'],
   409→    multiple: false,
   410→  };
   411→
   412→  const maxSizeBytes = config.maxSizeMB * 1024 * 1024;
   413→
   414→  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
   415→    const files = Array.from(e.target.files || []);
   416→    setUploadError('');
   417→
   418→    if (files.length === 0) return;
   419→
   420→    // Validate multiple files
   421→    if (!config.multiple && files.length > 1) {
   422→      setUploadError('Only one file is allowed');
   423→      e.target.value = ''; // Reset input
   424→      return;
   425→    }
   426→
   427→    // Validate each file
   428→    const validatedFiles: FileUploadAnswer[] = [];
   429→
   430→    for (const file of files) {
   431→      // Check file size
   432→      if (file.size > maxSizeBytes) {
   433→        setUploadError(`File "${file.name}" exceeds ${config.maxSizeMB}MB limit`);
   434→        e.target.value = '';
   435→        return;
   436→      }
   437→
   438→      // Check file type
   439→      const isAllowedType = config.allowedTypes.some((allowedType) => {
   440→        if (allowedType.endsWith('/*')) {
   441→          const category = allowedType.split('/')[0];
   442→          return file.type.startsWith(category + '/');
   443→        }
   444→        return file.type === allowedType;
   445→      });
   446→
   447→      if (!isAllowedType) {
   448→        setUploadError(
   449→          `File "${file.name}" type not allowed. Allowed types: ${config.allowedTypes.join(', ')}`
   450→        );
   451→        e.target.value = '';
   452→        return;
   453→      }
   454→
   455→      // Convert to base64
   456→      try {
   457→        const base64Data = await fileToBase64(file);
   458→        validatedFiles.push({
   459→          fileName: file.name,
   460→          fileType: file.type,
   461→          fileSize: file.size,
   462→          base64Data,
   463→          uploadedAt: new Date(),
   464→        });
   465→      } catch (err) {
   466→        setUploadError(`Failed to process file "${file.name}"`);
   467→        e.target.value = '';
   468→        return;
   469→      }
   470→    }
   471→
   472→    // Update value
   473→    if (config.multiple) {
   474→      // Append to existing files
   475→      const existingFiles = toFileArrayValue(value);
   476→      onChange([...existingFiles, ...validatedFiles]);
   477→    } else {
   478→      // Single file
   479→      onChange(validatedFiles[0]);
   480→    }
   481→
   482→    // Reset input so same file can be selected again
   483→    e.target.value = '';
   484→  };
   485→
   486→  const handleRemoveFile = (index?: number) => {
   487→    if (config.multiple && typeof index === 'number') {
   488→      const files = toFileArrayValue(value);
   489→      onChange(files.filter((_, i) => i !== index));
   490→    } else {
   491→      onChange(null);
   492→    }
   493→  };
   494→
   495→  // Get uploaded files as array using the helper
   496→  const uploadedFiles = toFileArrayValue(value);
   497→
   498→  return (
   499→    <div>
   500→      <label className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-1">
   501→        {field.label}
   502→        {field.required && <span className="text-red-500 ml-1">*</span>}
   503→      </label>
   504→      {field.description && (
   505→        <p className="text-xs text-text-light-tertiary dark:text-text-dark-tertiary mb-2">
   506→          {field.description}
   507→        </p>
   508→      )}
   509→
   510→      {/* Upload Button */}
   511→      <div className="relative">
   512→        <input
   513→          type="file"
   514→          id={`file-${field.id}`}
   515→          onChange={handleFileChange}
   516→          multiple={config.multiple}
   517→          accept={config.allowedTypes.join(',')}
   518→          required={field.required && uploadedFiles.length === 0}
   519→          className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10"
   520→        />
   521→        <div className="flex items-center gap-2 px-4 py-3 border-2 border-dashed border-border-light dark:border-border-dark rounded-lg hover:border-primary-light dark:hover:border-primary-dark transition-colors bg-surface-light dark:bg-surface-dark">
   522→          <Upload className="w-5 h-5 text-text-light-tertiary dark:text-text-dark-tertiary" />
   523→          <div className="flex-1">
   524→            <p className="text-sm text-text-light-primary dark:text-text-dark-primary">
   525→              {config.multiple ? 'Choose files or drag and drop' : 'Choose a file or drag and drop'}
   526→            </p>
   527→            <p className="text-xs text-text-light-tertiary dark:text-text-dark-tertiary">
   528→              Max {config.maxSizeMB}MB • {config.allowedTypes.join(', ')}
   529→            </p>
   530→          </div>
   531→        </div>
   532→      </div>
   533→
   534→      {/* Uploaded Files */}
   535→      {uploadedFiles.length > 0 && (
   536→        <div className="mt-3 space-y-2">
   537→          {uploadedFiles.map((file, index) => (
   538→            <div
   539→              key={index}
   540→              className="flex items-center gap-3 p-3 bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-lg"
   541→            >
   542→              <FileIcon className="w-5 h-5 text-primary-light dark:text-primary-dark shrink-0" />
   543→              <div className="flex-1 min-w-0">
   544→                <p className="text-sm font-medium text-text-light-primary dark:text-text-dark-primary truncate">
   545→                  {file.fileName}
   546→                </p>
   547→                <p className="text-xs text-text-light-tertiary dark:text-text-dark-tertiary">
   548→                  {formatFileSize(file.fileSize)}
   549→                </p>
   550→              </div>
