export function SelectField({ field, value, onChange, error }: FieldComponentProps) {
  return (
    <div>
      <label className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-1">
        {field.label}
        {field.required && <span className="text-red-500 ml-1">*</span>}
      </label>
      {field.description && (
        <p className="text-xs text-text-light-tertiary dark:text-text-dark-tertiary mb-2">
          {field.description}
        </p>
      )}
      <select
        value={toStringValue(value)}
        onChange={(e) => onChange(e.target.value)}
        required={field.required}
        className="w-full px-3 py-2 bg-background-light dark:bg-background-dark border border-border-light dark:border-border-dark rounded-lg focus:outline-none focus:ring-2 focus:ring-primary-light dark:focus:ring-primary-dark"
      >
        <option value="">Select an option...</option>
        {field.options?.map((option) => (
          <option key={option} value={option}>
            {option}
          </option>
        ))}
      </select>
      {error && <p className="text-xs text-red-500 mt-1">{error}</p>}
    </div>
  );
}

export function MultiSelectField({ field, value, onChange, error }: FieldComponentProps) {
  const selectedValues = toStringArrayValue(value);

  const handleToggle = (option: string) => {
    if (selectedValues.includes(option)) {
      onChange(selectedValues.filter((v) => v !== option));
    } else {
      onChange([...selectedValues, option]);
    }
  };

  return (
    <div>
      <label className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-1">
        {field.label}
        {field.required && <span className="text-red-500 ml-1">*</span>}
      </label>
      {field.description && (
        <p className="text-xs text-text-light-tertiary dark:text-text-dark-tertiary mb-2">
          {field.description}
        </p>
      )}
      <div className="space-y-2">
        {field.options?.map((option) => (
          <label key={option} className="flex items-center gap-2 cursor-pointer">
            <input
              type="checkbox"
              checked={selectedValues.includes(option)}
              onChange={() => handleToggle(option)}
              className="w-4 h-4"
            />
            <span className="text-sm text-text-light-primary dark:text-text-dark-primary">
              {option}
            </span>
          </label>
        ))}
      </div>
      {error && <p className="text-xs text-red-500 mt-1">{error}</p>}
    </div>
  );
}

export function RadioField({ field, value, onChange, error }: FieldComponentProps) {
  return (
    <div>
      <label className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-1">
        {field.label}
        {field.required && <span className="text-red-500 ml-1">*</span>}
      </label>
      {field.description && (
        <p className="text-xs text-text-light-tertiary dark:text-text-dark-tertiary mb-2">
          {field.description}
