        {[1, 2, 3, 4, 5].map((star) => (
          <button
            key={star}
            type="button"
            onClick={() => onChange(star)}
            className={`text-3xl transition-colors ${
              star <= rating
                ? 'text-yellow-500'
                : 'text-text-light-tertiary dark:text-text-dark-tertiary'
            }`}
          >
            ★
          </button>
        ))}
        {rating > 0 && (
          <span className="ml-2 text-sm text-text-light-secondary dark:text-text-dark-secondary">
