              num === scaleValue
                ? 'bg-primary-light dark:bg-primary-dark text-white'
                : 'bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark hover:bg-surface-hover-light dark:hover:bg-surface-hover-dark'
            }`}
