/**
 * Field List Component
 * Display and manage list of form fields with reordering
 */

import type { FormField } from '../../types/forms';
import { GripVertical, Edit, Trash2, Copy, ChevronUp, ChevronDown } from 'lucide-react';

interface FieldListProps {
  fields: FormField[];
  onEdit: (field: FormField) => void;
  onDelete: (id: string) => void;
  onDuplicate: (field: FormField) => void;
  onMoveUp: (id: string) => void;
  onMoveDown: (id: string) => void;
}

export function FieldList({
  fields,
  onEdit,
  onDelete,
  onDuplicate,
  onMoveUp,
  onMoveDown,
}: FieldListProps) {
  const sortedFields = [...fields].sort((a, b) => a.order - b.order);

  if (fields.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center p-8 text-center border-2 border-dashed border-border-light dark:border-border-dark rounded-lg">
        <p className="text-text-light-secondary dark:text-text-dark-secondary">
          No fields yet. Click "Add Field" to get started.
        </p>
      </div>
    );
  }

  return (
    <div className="space-y-2">
      {sortedFields.map((field, index) => (
        <FieldListItem
          key={field.id}
          field={field}
          isFirst={index === 0}
          isLast={index === sortedFields.length - 1}
          onEdit={() => onEdit(field)}
          onDelete={() => onDelete(field.id)}
          onDuplicate={() => onDuplicate(field)}
          onMoveUp={() => onMoveUp(field.id)}
          onMoveDown={() => onMoveDown(field.id)}
        />
      ))}
    </div>
  );
}

interface FieldListItemProps {
  field: FormField;
  isFirst: boolean;
  isLast: boolean;
  onEdit: () => void;
  onDelete: () => void;
  onDuplicate: () => void;
  onMoveUp: () => void;
  onMoveDown: () => void;
}

function FieldListItem({
  field,
  isFirst,
  isLast,
  onEdit,
  onDelete,
  onDuplicate,
  onMoveUp,
  onMoveDown,
}: FieldListItemProps) {
  const getFieldTypeLabel = (type: string): string => {
    const labels: Record<string, string> = {
      text: 'Text',
      textarea: 'Text Area',
      number: 'Number',
      date: 'Date',
      time: 'Time',
      select: 'Select',
      multiselect: 'Multi-Select',
      radio: 'Radio',
      checkbox: 'Checkbox',
      rating: 'Rating',
      scale: 'Scale',
    };
    return labels[type] || type;
  };

  return (
    <div className="flex items-center gap-2 p-3 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg hover:shadow-md transition-shadow group">
      {/* Drag Handle (visual only) */}
      <div className="flex-shrink-0 text-text-light-tertiary dark:text-text-dark-tertiary cursor-grab">
        <GripVertical className="w-5 h-5" />
      </div>

      {/* Field Info */}
      <div className="flex-1 min-w-0">
        <div className="flex items-center gap-2">
          <h4 className="font-medium text-text-light-primary dark:text-text-dark-primary truncate">
            {field.label}
          </h4>
          {field.required && (
            <span className="text-xs px-1.5 py-0.5 bg-red-500/10 text-red-500 rounded">
              Required
            </span>
          )}
        </div>
        <div className="flex items-center gap-2 text-xs text-text-light-secondary dark:text-text-dark-secondary mt-1">
          <span className="px-2 py-0.5 bg-primary-light/10 dark:bg-primary-dark/10 text-primary-light dark:text-primary-dark rounded">
            {getFieldTypeLabel(field.type)}
          </span>
          {field.description && (
            <span className="truncate">{field.description}</span>
          )}
        </div>
      </div>

      {/* Actions */}
      <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
        {/* Move Up/Down */}
        <button
          onClick={onMoveUp}
          disabled={isFirst}
          className="p-1 hover:bg-surface-hover-light dark:hover:bg-surface-hover-dark rounded disabled:opacity-30 disabled:cursor-not-allowed"
          title="Move up"
        >
          <ChevronUp className="w-4 h-4" />
        </button>
        <button
          onClick={onMoveDown}
          disabled={isLast}
          className="p-1 hover:bg-surface-hover-light dark:hover:bg-surface-hover-dark rounded disabled:opacity-30 disabled:cursor-not-allowed"
          title="Move down"
        >
          <ChevronDown className="w-4 h-4" />
        </button>

        {/* Edit */}
        <button
          onClick={onEdit}
          className="p-1 hover:bg-surface-hover-light dark:hover:bg-surface-hover-dark rounded"
          title="Edit field"
        >
          <Edit className="w-4 h-4" />
        </button>

        {/* Duplicate */}
        <button
          onClick={onDuplicate}
          className="p-1 hover:bg-surface-hover-light dark:hover:bg-surface-hover-dark rounded"
          title="Duplicate field"
        >
          <Copy className="w-4 h-4" />
        </button>

        {/* Delete */}
        <button
          onClick={onDelete}
          className="p-1 hover:bg-red-500/10 text-red-500 rounded"
          title="Delete field"
        >
          <Trash2 className="w-4 h-4" />
        </button>
      </div>
    </div>
  );
}

/**
 * Form Preview Component
 * Interactive preview of form with conditional logic and calculated fields
 */

import { useState } from 'react';
import { Eye, RotateCcw } from 'lucide-react';
import type { FormTemplate } from '../../types/forms';
import { FormRenderer } from '../FormRenderer/FormRenderer';

interface FormPreviewProps {
  form: FormTemplate;
  onClose: () => void;
}

export function FormPreview({ form, onClose }: FormPreviewProps) {
  const [responses, setResponses] = useState<Record<string, any>[]>([]);
  const [showSuccessMessage, setShowSuccessMessage] = useState(false);

  const handleSubmit = (answers: Record<string, any>, metadata?: any) => {
    // Add response to list
    setResponses([...responses, { answers, metadata, timestamp: new Date() }]);

    // Show success message
    setShowSuccessMessage(true);

    // Reset after 2 seconds
    setTimeout(() => {
      setShowSuccessMessage(false);
    }, 2000);
  };

  const handleReset = () => {
    setResponses([]);
    setShowSuccessMessage(false);
  };

  return (
    <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
      <div className="bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg max-w-4xl w-full max-h-[90vh] overflow-hidden flex flex-col">
        {/* Header */}
        <div className="flex items-center justify-between p-4 border-b border-border-light dark:border-border-dark bg-surface-light dark:bg-surface-dark">
          <div className="flex items-center gap-3">
            <Eye className="w-5 h-5 text-accent-cyan" />
            <div>
              <h2 className="text-lg font-semibold text-text-light-primary dark:text-text-dark-primary">
                Form Preview
              </h2>
              <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
                Test conditional logic and calculated fields
              </p>
            </div>
          </div>
          <div className="flex items-center gap-2">
            <button
              onClick={handleReset}
              className="flex items-center gap-2 px-3 py-2 text-sm bg-surface-hover-light dark:bg-surface-hover-dark rounded-lg hover:bg-border-light dark:hover:bg-border-dark transition-colors"
              aria-label="Reset preview"
            >
              <RotateCcw className="w-4 h-4" />
              Reset
            </button>
            <button
              onClick={onClose}
              className="px-4 py-2 text-sm bg-primary-light dark:bg-primary-dark text-white rounded-lg hover:opacity-90"
            >
              Close
            </button>
          </div>
        </div>

        {/* Content */}
        <div className="flex-1 overflow-y-auto p-6">
          {/* Success Message */}
          {showSuccessMessage && (
            <div className="mb-4 p-4 bg-accent-green/10 border border-accent-green rounded-lg">
              <p className="text-accent-green font-medium">
                ✓ Form submitted successfully! (Preview mode - not saved)
